// Minimal health-check server — CommonJS syntax to avoid "type":module requirement
const http = require('http')

const PORT = process.env.PORT || process.env.WEB_PORT || 8080
const server = http.createServer((req, res) => {
  res.writeHead(200, { 'Content-Type': 'application/json' })
  res.end(JSON.stringify({
    ok: true,
    port: PORT,
    env_port: process.env.PORT,
    node: process.version,
    cwd: process.cwd()
  }))
})

server.listen(PORT, '0.0.0.0', () => {
  console.log(`[minimal] listening on 0.0.0.0:${PORT}  cwd=${process.cwd()}  node=${process.version}`)
})
